#!/usr/bin/env node
/**
 * Run Tests Directly (Without Deployment).
 *
 * Runs tests directly against code without Docker deployment.
 * Auto-generated by datrix-codegen-typescript. Do not edit manually.
 *
 * Usage:
 *   node tests/unit-tests.js                  # Run unit tests
 *   node tests/unit-tests.js --unit           # Run unit tests only
 *   node tests/unit-tests.js --integration    # Run integration tests (needs TEST_DATABASE_URL)
 *   node tests/unit-tests.js --all            # Run both unit and integration tests
 *   node tests/unit-tests.js --no-save        # Don't save output to files
 *   node tests/unit-tests.js --output-dir X   # Custom output directory
 *   node tests/unit-tests.js --parallel       # Run service tests in parallel
 *   node tests/unit-tests.js --coverage       # Run with coverage report
 */
'use strict';

const { execSync, spawn } = require('child_process');
const fs = require('fs');
const path = require('path');

const SERVICES = [
  { name: 'ecommerce.UserService', dir: 'ecommerce_user_service', port: 8000 },
  { name: 'ecommerce.ProductService', dir: 'ecommerce_product_service', port: 8001 },
  { name: 'ecommerce.OrderService', dir: 'ecommerce_order_service', port: 8002 },
  { name: 'ecommerce.PaymentService', dir: 'ecommerce_payment_service', port: 8003 },
  { name: 'ecommerce.ShippingService', dir: 'ecommerce_shipping_service', port: 8004 },
];

// ANSI colour helpers
const GREEN = '\x1b[92m';
const CYAN = '\x1b[96m';
const YELLOW = '\x1b[93m';
const RED = '\x1b[91m';
const RESET = '\x1b[0m';

let summaryLogPath = null;

function log(colour, msg) {
  console.log(`${colour}${msg}${RESET}`);
  if (summaryLogPath) {
    fs.appendFileSync(summaryLogPath, msg + '\n', 'utf-8');
  }
}

function printSuccess(msg) { log(GREEN, msg); }
function printInfo(msg)    { log(CYAN, msg); }
function printWarning(msg) { log(YELLOW, `WARNING: ${msg}`); }
function printError(msg)   { log(RED, `ERROR: ${msg}`); }

function stripAnsi(str) {
  return str.replace(/\x1b\[[0-9;]*m/g, '');
}

/**
 * Load optional test-config.json.
 */
function loadTestConfig(configPath) {
  if (!fs.existsSync(configPath)) return null;
  try {
    return JSON.parse(fs.readFileSync(configPath, 'utf-8'));
  } catch (err) {
    printWarning(`Failed to load test config from ${configPath}: ${err.message}`);
    return null;
  }
}

/**
 * Parse test statistics from Jest output.
 * Looks for patterns like:
 *   Test Suites: 1 failed, 50 passed, 51 total
 *   Tests:       2 failed, 35 passed, 37 total
 */
function parseTestStatistics(output) {
  const result = { passed: 0, failed: 0, errors: 0, skipped: 0, suiteFailed: false };
  if (!output) return result;

  // Check for test suite failures: "Test Suites: 1 failed, ..."
  const suitesLine = output.match(/Test Suites:\s+(.+total)/);
  if (suitesLine) {
    const suiteFailedMatch = suitesLine[1].match(/(\d+) failed/);
    if (suiteFailedMatch && parseInt(suiteFailedMatch[1], 10) > 0) {
      result.suiteFailed = true;
      // Treat suite failures as errors (suite couldn't even run)
      result.errors += parseInt(suiteFailedMatch[1], 10);
    }
  }

  // Jest summary line: "Tests:  2 failed, 35 passed, 37 total"
  const testsLine = output.match(/Tests:\s+(.+total)/);
  if (testsLine) {
    const passedMatch = testsLine[1].match(/(\d+) passed/);
    const failedMatch = testsLine[1].match(/(\d+) failed/);
    const skippedMatch = testsLine[1].match(/(\d+) skipped/);
    if (passedMatch) result.passed = parseInt(passedMatch[1], 10);
    if (failedMatch) result.failed = parseInt(failedMatch[1], 10);
    if (skippedMatch) result.skipped = parseInt(skippedMatch[1], 10);
    return result;
  }

  // Fallback: "Total Passed: X" format (datrix runner)
  const totalPassed = output.match(/Total Passed:\s*(\d+)/);
  if (totalPassed) result.passed = parseInt(totalPassed[1], 10);
  const totalFailed = output.match(/Total Failed:\s*(\d+)/);
  if (totalFailed) result.failed = parseInt(totalFailed[1], 10);
  const totalErrors = output.match(/Total Errors:\s*(\d+)/);
  if (totalErrors) result.errors = parseInt(totalErrors[1], 10);
  const totalSkipped = output.match(/Total Skipped:\s*(\d+)/);
  if (totalSkipped) result.skipped = parseInt(totalSkipped[1], 10);

  return result;
}

function parseArgs() {
  const args = {
    unit: false,
    integration: false,
    all: false,
    noSave: false,
    outputDir: '',
    parallel: false,
    maxWorkers: 4,
    coverage: false,
  };
  for (let i = 2; i < process.argv.length; i++) {
    const arg = process.argv[i];
    if (arg === '--unit') args.unit = true;
    else if (arg === '--integration') args.integration = true;
    else if (arg === '--all') args.all = true;
    else if (arg === '--no-save') args.noSave = true;
    else if (arg === '--parallel') args.parallel = true;
    else if (arg === '--coverage') args.coverage = true;
    else if (arg === '--output-dir' && process.argv[i + 1]) {
      args.outputDir = process.argv[++i];
    } else if (arg === '--max-workers' && process.argv[i + 1]) {
      args.maxWorkers = parseInt(process.argv[++i], 10);
    }
  }
  return args;
}

/**
 * Run Jest tests in a service directory with the given config.
 * Returns { output, exitCode }.
 *
 * @param {string} serviceDir - absolute path to the service directory
 * @param {object} args - parsed CLI arguments
 * @param {string|null} jestConfigFile - Jest config file name, or null for default
 */
function runServiceTests(serviceDir, args, jestConfigFile) {
  const npmCmd = process.platform === 'win32' ? 'npm.cmd' : 'npm';
  const testArgs = [npmCmd, 'test', '--', '--forceExit', '--detectOpenHandles', '--no-cache'];

  if (jestConfigFile) {
    testArgs.push('--config', jestConfigFile);
  }

  if (args.coverage) {
    testArgs.push('--coverage');
  }

  return new Promise((resolve) => {
    const proc = spawn(testArgs[0], testArgs.slice(1), {
      cwd: serviceDir,
      stdio: ['pipe', 'pipe', 'pipe'],
      shell: process.platform === 'win32',
      env: { ...process.env, NODE_ENV: 'test', CI: 'true' },
    });

    const chunks = [];
    proc.stdout.on('data', (data) => {
      chunks.push(data);
      process.stdout.write(data);
    });
    proc.stderr.on('data', (data) => {
      chunks.push(data);
      process.stderr.write(data);
    });

    proc.on('close', (code) => {
      const output = Buffer.concat(chunks).toString('utf-8');
      resolve({ output, exitCode: code ?? 1 });
    });
  });
}

/**
 * Install npm dependencies if node_modules is missing or package.json changed.
 */
function ensureInstalled(serviceDir, label) {
  const nodeModules = path.join(serviceDir, 'node_modules');
  const pkgJson = path.join(serviceDir, 'package.json');
  let needsInstall = !fs.existsSync(nodeModules);
  if (!needsInstall && fs.existsSync(pkgJson)) {
    const pkgMtime = fs.statSync(pkgJson).mtimeMs;
    const nmMtime = fs.statSync(nodeModules).mtimeMs;
    if (pkgMtime > nmMtime) {
      needsInstall = true;
    }
  }
  if (needsInstall) {
    printInfo(`  Installing dependencies for ${label}...`);
    try {
      const npmCmd = process.platform === 'win32' ? 'npm.cmd' : 'npm';
      execSync(`${npmCmd} install`, { cwd: serviceDir, stdio: 'pipe' });
    } catch (err) {
      printError(`  npm install failed for ${label}: ${err.message}`);
      return false;
    }
  }
  return true;
}

async function main() {
  const args = parseArgs();
  const scriptDir = __dirname;
  const projectPath = path.resolve(scriptDir, '..');

  // Load test configuration
  const configPath = path.join(scriptDir, 'test-config.json');
  const config = loadTestConfig(configPath);

  // Setup output directory
  let saveOutput = !args.noSave;
  let outputDir = null;

  if (saveOutput) {
    const now = new Date();
    const pad = (n) => String(n).padStart(2, '0');
    const timestamp = `${now.getFullYear()}${pad(now.getMonth() + 1)}${pad(now.getDate())}-${pad(now.getHours())}${pad(now.getMinutes())}${pad(now.getSeconds())}`;
    outputDir = args.outputDir
      ? path.resolve(args.outputDir)
      : path.join(projectPath, '.test_results', `unit-tests-${timestamp}`);
    fs.mkdirSync(outputDir, { recursive: true });
    summaryLogPath = path.join(outputDir, 'unit-tests-summary.log');
    fs.writeFileSync(summaryLogPath, [
      '='.repeat(40),
      'Run Tests Summary Log',
      '='.repeat(40),
      `Project: ${projectPath}`,
      `Timestamp: ${new Date().toISOString()}`,
      '='.repeat(40),
      '',
      '',
    ].join('\n'), 'utf-8');
    printInfo(`Test output will be saved to: ${outputDir}`);
  }

  printInfo('='.repeat(40));
  printInfo(`Running Tests: ${projectPath}`);
  printInfo('='.repeat(40));

  // Resolve service directories
  const serviceDirs = SERVICES
    .map((svc) => ({ ...svc, fullPath: path.join(projectPath, svc.dir) }))
    .filter((svc) => {
      const pkgPath = path.join(svc.fullPath, 'package.json');
      return fs.existsSync(pkgPath);
    });

  if (serviceDirs.length === 0) {
    printError('No services with package.json found in project.');
    process.exit(1);
  }

  printInfo(`Found ${serviceDirs.length} services: ${serviceDirs.map((s) => s.dir).join(', ')}`);
  printInfo('');
  printInfo('Running tests...');
  printInfo('='.repeat(40));

  let totalPassed = 0;
  let totalFailed = 0;
  let totalErrors = 0;
  let totalSkipped = 0;
  const failedServices = [];

  // Determine which test phases to run
  const runUnit = args.all || args.unit || (!args.integration);
  const runIntegration = args.all || args.integration;

  for (const svc of serviceDirs) {
    printInfo('');
    printInfo(`Testing: ${svc.dir}`);
    printInfo('-'.repeat(40));

    if (!ensureInstalled(svc.fullPath, svc.dir)) {
      totalErrors += 1;
      failedServices.push(svc.dir);
      continue;
    }

    let svcFailed = false;

    // Unit tests (default jest config)
    if (runUnit) {
      const { output, exitCode } = await runServiceTests(svc.fullPath, args, null);
      const stats = parseTestStatistics(output);
      totalPassed += stats.passed;
      totalFailed += stats.failed;
      totalErrors += stats.errors;
      totalSkipped += stats.skipped;

      if (exitCode !== 0 || stats.failed > 0 || stats.errors > 0) {
        svcFailed = true;
      }

      if (!svcFailed && stats.passed > 0) {
        printSuccess(`  UNIT PASSED: ${stats.passed} tests (${stats.skipped} skipped)`);
      } else if (stats.failed > 0 || stats.errors > 0) {
        printError(`  UNIT FAILED: ${stats.passed} passed, ${stats.failed} failed, ${stats.errors} errors`);
      } else if (exitCode !== 0 && stats.passed === 0) {
        printError('  UNIT FAILED: Test suite failed to run (exitCode: ' + exitCode + ')');
      } else if (stats.passed === 0) {
        printWarning('  UNIT: No tests were collected or run');
      }

      if (saveOutput && outputDir) {
        const logFile = path.join(outputDir, `${svc.dir}-unit-tests.log`);
        fs.writeFileSync(logFile, stripAnsi(output), 'utf-8');
      }
    }

    // Integration tests (jest-integration.config.ts)
    if (runIntegration) {
      const integrationConfig = path.join(svc.fullPath, 'jest-integration.config.ts');
      if (fs.existsSync(integrationConfig)) {
        if (!process.env.TEST_DATABASE_URL) {
          printWarning(`  INTEGRATION SKIPPED: TEST_DATABASE_URL not set for ${svc.dir}`);
        } else {
          printInfo(`  Running integration tests for ${svc.dir}...`);
          const { output, exitCode } = await runServiceTests(
            svc.fullPath, args, 'jest-integration.config.ts',
          );
          const stats = parseTestStatistics(output);
          totalPassed += stats.passed;
          totalFailed += stats.failed;
          totalErrors += stats.errors;
          totalSkipped += stats.skipped;

          if (exitCode !== 0 || stats.failed > 0 || stats.errors > 0) {
            svcFailed = true;
          }

          if (stats.passed > 0 && stats.failed === 0 && stats.errors === 0) {
            printSuccess(`  INTEGRATION PASSED: ${stats.passed} tests`);
          } else if (stats.failed > 0 || stats.errors > 0) {
            printError(`  INTEGRATION FAILED: ${stats.passed} passed, ${stats.failed} failed`);
          }

          if (saveOutput && outputDir) {
            const logFile = path.join(outputDir, `${svc.dir}-integration-tests.log`);
            fs.writeFileSync(logFile, stripAnsi(output), 'utf-8');
          }
        }
      }
    }

    if (svcFailed) {
      failedServices.push(svc.dir);
    }
  }

  // Summary
  printInfo('');
  printInfo('='.repeat(40));
  printInfo('Test Summary');
  printInfo('='.repeat(40));
  printInfo(`Total Passed:  ${totalPassed}`);
  if (totalFailed > 0) printError(`Total Failed:  ${totalFailed}`);
  if (totalErrors > 0) printError(`Total Errors:  ${totalErrors}`);
  if (totalSkipped > 0) printInfo(`Total Skipped: ${totalSkipped}`);

  if (failedServices.length > 0) {
    printError('');
    printError(`Failed services: ${failedServices.join(', ')}`);
  }

  const totalIssues = totalFailed + totalErrors;
  if (totalIssues > 0 || failedServices.length > 0) {
    printError('');
    printError('Tests FAILED!');
    process.exit(1);
  } else if (totalPassed === 0) {
    printError('');
    printError('NO TESTS COLLECTED — nothing passed!');
    process.exit(1);
  } else {
    printSuccess('');
    printSuccess('All tests PASSED!');
    process.exit(0);
  }
}

main().catch((err) => {
  printError(`Unexpected error: ${err.message}`);
  process.exit(1);
});
